int test_calculation_reset(int a, int b, int c) {
    // 1. Create reactive variables
    reaction::Var<int> var_a(a);
    reaction::Var<int> var_b(b);
    reaction::Var<int> var_c(c);

    // 2. Create initial calculation (sum of a and b)
    reaction::Calc<int> calc([&var_a, &var_b]() {
        return var_a.get() + var_b.get();
    });

    // 3. Reset calculation with different dependencies (product of a and c)
    calc.reset([&var_a, &var_c]() {
        return var_a.get() * var_c.get();
    });

    // 4. Return result after reset
    return calc.get();
}

}  // namespace test_reaction

