    reaction::rvar<int> counter(10);

    // 2. Create counter to track calculation evaluations
    int calc_evaluations = 0;

    // 3. Create calculation to track value
    auto value_calc = reaction::rcalc<int>([&]() {
        calc_evaluations++;
        return counter.get();
    });

    // 4. Apply atomic addition
    counter.atomic_add(5);

    // 5. Get value after addition
    int after_add = value_calc.get();

    // 6. Apply atomic multiplication
    counter.atomic_multiply(3);

    // 7. Get value after multiplication
    int after_mult = value_calc.get();

    // 8. Apply atomic bitwise AND
    counter.atomic_and(0x0F); // 15 in decimal

    // 9. Get value after bitwise AND
    int after_and = value_calc.get();

    // 10. Apply atomic left shift
    counter.atomic_left_shift(2);

    // 11. Get value after shift
    int after_shift = value_calc.get();

    // 12. Apply post-increment
    int post_inc_return = counter.atomic_post_increment();

    // 13. Get final value
    int final_val = value_calc.get();

    // 14. Return atomic compound snapshot
    return AtomicCompoundSnapshot{
        after_add,
        after_mult,
        after_and,
        after_shift,
