    snapshot.initialSum = sum_expr.evaluate();
    snapshot.initialNegatedSum = negated_expr.evaluate();
    snapshot.initialChainedValue = chained_expr.evaluate();

    // 6. Update variables to trigger recomputation
    var_a.set(a + 10);
    var_c.set(c * 2);

    // 7. Get updated expression values
    snapshot.updatedSum = sum_expr.evaluate();
    snapshot.updatedNegatedSum = negated_expr.evaluate();
    snapshot.updatedChainedValue = chained_expr.evaluate();

    return snapshot;
}

